import{_ as a,c as r,a as n,o as c}from"./app-B4hlhHa_.js";const s={};function d(i,e){return c(),r("div",null,e[0]||(e[0]=[n('<blockquote><p>All in AI，看见未来。 每天精选最值得读的AI文章，帮你筛掉时代的噪音。 以简讯见广度，以深读见洞察。 技术、趋势、思考，一站式掌握AI世界。 欢迎关注公众号「AI Reading Hub」，获取更多AI资讯和技术文章。</p></blockquote><h1 id="_2026-06-17-资讯日报" tabindex="-1"><a class="header-anchor" href="#_2026-06-17-资讯日报"><span>2026-06-17 资讯日报</span></a></h1><h2 id="新闻资讯" tabindex="-1"><a class="header-anchor" href="#新闻资讯"><span>新闻资讯</span></a></h2><h3 id="科学家-小鼠戒糖反倒血糖更差" tabindex="-1"><a class="header-anchor" href="#科学家-小鼠戒糖反倒血糖更差"><span>科学家：小鼠戒糖反倒血糖更差</span></a></h3><p>科威特 Dasman 糖尿病研究所：小鼠实验显示，完全不吃糖的低脂饮食会使小鼠血糖失控、肠道细菌紊乱。这提示均衡营养比单纯戒糖重要，饮食建议或转向维护肠道微生物组。<a href="https://mp.weixin.qq.com/s?__biz=MzA3NTIyODUzNA==&amp;chksm=864ddb6c744fef2ef137c1bf549f62d90cb3353df78b0da9c43015a1f7ef3ac99e364a0b626c&amp;idx=1&amp;mid=2649798747&amp;sn=c6ac92d618ea4bc8adaed006826c038a#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="微软纳德拉-ai时代企业要建学习闭环" tabindex="-1"><a class="header-anchor" href="#微软纳德拉-ai时代企业要建学习闭环"><span>微软纳德拉：AI时代企业要建学习闭环</span></a></h3><p>微软CEO纳德拉：AI模型变强，人的判断力更值钱。企业要构建AI学习闭环，让人力资本与AI能力叠加。可通过私有评测、强化学习环境和知识库构建核心知识产权。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3Mzg5MjY3Nw==&amp;chksm=cf9df5446196ef3a049e9e86a69fd2f472215c0bfe37313b2f1a38edccd10785ec2722261aee&amp;idx=2&amp;mid=2247526485&amp;sn=43018939aae03d0acd90a78cc82a6755#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="章鱼动力获5000万美元融资-推动物理ai进阶" tabindex="-1"><a class="header-anchor" href="#章鱼动力获5000万美元融资-推动物理ai进阶"><span>章鱼动力获5000万美元融资，推动物理AI进阶</span></a></h3><p>章鱼动力3个月累计融资近10亿，本轮5000万美元。其提出世界模型三阶段和物理AI五级进阶体系，以SYNTH架构构建闭环，创始人都大龙认为物理AI要脑手一体。<a href="https://mp.weixin.qq.com/s?__biz=MzA5ODEzMjIyMA==&amp;chksm=913a09e566e7c9aac65df8a0fb7962761cef9f5ed700e3c1d9dbdd348c83bc49aa5bf134e3b7&amp;idx=1&amp;mid=2247736892&amp;sn=d88ad9bc5129a1396057a8f3bdfad11c#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="deepseek新模型灰度-获500亿融资加速" tabindex="-1"><a class="header-anchor" href="#deepseek新模型灰度-获500亿融资加速"><span>DeepSeek新模型灰度，获500亿融资加速</span></a></h3><p>群传DeepSeek灰度新模型，思考模式有变化，bug修复但幻觉严重。同时，获500亿首轮融资，梁文锋占40%，投资方无投票权，钱或用于芯片和数据中心，有望下半年加速。<a href="https://mp.weixin.qq.com/s?__biz=MzkxNjcyNTk2NA==&amp;chksm=c052bc0e9413da464d46a4ec649340280d049aa2101fd55b39a817a61057f464d3b9490d2fbc&amp;idx=1&amp;mid=2247493645&amp;sn=251edb213411ad634a43044cee36b43b#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="spacex零现金吞ai编程工具cursor" tabindex="-1"><a class="header-anchor" href="#spacex零现金吞ai编程工具cursor"><span>SpaceX零现金吞AI编程工具Cursor</span></a></h3><p>SpaceX：IPO第四天以600亿美元全股票收购Cursor。Cursor增长快但份额降、算力缺，收购是马斯克算力布局收官，还将推联合模型与编程代理工具。<a href="https://mp.weixin.qq.com/s?__biz=MzIzNjc1NzUzMw==&amp;chksm=e9c92603b7f26798d64cf59126705a2671126edada9b1068c857e8406349bd991e6326d5d657&amp;idx=1&amp;mid=2247897842&amp;sn=eb63897f77af1f20f7a118ca579de6e2#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="spacex-600亿美元收购ai编程工具cursor" tabindex="-1"><a class="header-anchor" href="#spacex-600亿美元收购ai编程工具cursor"><span>SpaceX 600亿美元收购AI编程工具Cursor</span></a></h3><p>Cursor CEO Michael Truell：公司要训练自有模型，不能依赖Claude。SpaceX以600亿美元收购Cursor母公司，因前者有算力缺产品，后者有产品缺算力，交易能否成功取决于自研模型。<a href="https://mp.weixin.qq.com/s?__biz=MzA3NTIyODUzNA==&amp;chksm=860ee27db8081767e45aa67f2e3bb41d22cbf334c4d1c5c739254eddf36783ea221746a4367d&amp;idx=1&amp;mid=2649798744&amp;sn=76c3872dca51af51093f7a48b70225a7#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="spacex-600-亿收购-cursor-马斯克补-ai-短板" tabindex="-1"><a class="header-anchor" href="#spacex-600-亿收购-cursor-马斯克补-ai-短板"><span>SpaceX 600 亿收购 Cursor，马斯克补 AI 短板</span></a></h3><p>SpaceX 600 亿美元收购 Cursor。因 xAI 在 AI 编程领域落后，收购可补短板，且 Cursor 有开发者入口价值，缺算力，并入后能获支撑，体现马斯克极端资源换时间风格。<a href="https://mp.weixin.qq.com/s?__biz=MzU1NDA4NjU2MA==&amp;chksm=facb47b38bcd42f6fe196e00ac9c0c75b022065939a54082c3c8e3cdf5ee69a58125a4e475d6&amp;idx=1&amp;mid=2247663625&amp;sn=ba3609f93ee14aa9484ab350db9ed815#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="智谱glm-5-2拿下ai编程开源第一" tabindex="-1"><a class="header-anchor" href="#智谱glm-5-2拿下ai编程开源第一"><span>智谱GLM - 5.2拿下AI编程开源第一</span></a></h3><p>智谱GLM - 5.2在AI编程测评中表现出色，拿下开源界编程第一、全球第二。实测显示其支持1M上下文，在长程任务领先，标志国产开源模型进入开发者工作流和硬核工程阶段。<a href="https://mp.weixin.qq.com/s?__biz=MzIzNjc1NzUzMw==&amp;chksm=e9a4bb87a5ae0b7d8ad904d634d7353da4c87dff1223fa394fc23e4fd8ff544103c5947a8491&amp;idx=1&amp;mid=2247897921&amp;sn=cab67dd27d1b6e26b248d06f404b9375#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="cursor新模型-规模比肩opus、gpt将发布" tabindex="-1"><a class="header-anchor" href="#cursor新模型-规模比肩opus、gpt将发布"><span>Cursor新模型：规模比肩Opus、GPT将发布</span></a></h3><p>Cursor CEO Michael Truell：新1.5万亿+参数模型在超10万GPU预训练，规模与Opus、GPT相当。认为Anthropic难被追上，Google、OpenAI等各有问题，新模型几周内发布。<a href="https://mp.weixin.qq.com/s?__biz=MzA3MzI4MjgzMw==&amp;chksm=85bf0fafcd3c9c118cea22c8b6166b328c19a191605df8a3d9062c5ac45a8ce88ee9ac6d125d&amp;idx=1&amp;mid=2651039480&amp;sn=b6eeb746cfa680a850d85e511b3cea50#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="马斯克600亿收购cursor-抢搭asi末班车" tabindex="-1"><a class="header-anchor" href="#马斯克600亿收购cursor-抢搭asi末班车"><span>马斯克600亿收购Cursor，抢搭ASI末班车</span></a></h3><p>马斯克：600亿收购Cursor，为搭上ASI末班车。其xAI发展不佳，而Cursor被Anthropic打压。编程工具赛道竞争激烈，Cursor是独立入口，新模型若成功或能改变局面。<a href="https://mp.weixin.qq.com/s?__biz=MzI3MTA0MTk1MA==&amp;chksm=f0d2e90ef880fa757cdb7a03086859045465121ad82ddcb514747eff9598ca5c159e14f8dd13&amp;idx=1&amp;mid=2652707520&amp;sn=1054a2f23382bdd7a3b198820dd05fbc#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="产品应用" tabindex="-1"><a class="header-anchor" href="#产品应用"><span>产品应用</span></a></h2><h3 id="淘宝主播agent-harness工程实战揭秘" tabindex="-1"><a class="header-anchor" href="#淘宝主播agent-harness工程实战揭秘"><span>淘宝主播Agent：Harness工程实战揭秘</span></a></h3><p>淘宝：为让主播Agent在高风险直播场景可用、可控、可演化，采用Harness工程。通过六元组划清边界，做好上下文工程等实战，构建特色记忆体系，使其越用越懂主播。<a href="https://mp.weixin.qq.com/s?__biz=MzIzOTU0NTQ0MA==&amp;chksm=e8305c815d928b03d911d0babb8f1779c865406ab369bcbd52af44c3e6dbdb728a234cf040fb&amp;idx=1&amp;mid=2247561174&amp;sn=dbc62f1f8688bac841edb9c3829a88cf#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="tokendance-首发开放智谱-glm-5-2" tabindex="-1"><a class="header-anchor" href="#tokendance-首发开放智谱-glm-5-2"><span>TokenDance 首发开放智谱 GLM-5.2</span></a></h3><p>TokenDance 平台：今日首发接入智谱 GLM-5.2 并开放使用。该平台可让用户一站式调用多模型，此前已对 GLM-5.2 内测适配，将推动新模型高效进入实际场景。<a href="https://mp.weixin.qq.com/s?__biz=MzYyMTY1NDA0Nw==&amp;chksm=fe38334eb12086a454a61a12e9711680e75c936a375388a7a840a9929e9d333ac9849394b0ab&amp;idx=1&amp;mid=2247518982&amp;sn=5dc2df070b290a6083f2c5a73eeea395#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="推荐文章" tabindex="-1"><a class="header-anchor" href="#推荐文章"><span>推荐文章</span></a></h2><h3 id="claw-swe-bench-揭秘编程agent评测真相" tabindex="-1"><a class="header-anchor" href="#claw-swe-bench-揭秘编程agent评测真相"><span>Claw - SWE - Bench：揭秘编程Agent评测真相</span></a></h3><p>基元律动等机构：发布Claw - SWE - Bench基准，拆分模型、harness和任务集。实验显示harness对成绩影响大，还解决通用Agent评测难题，推出低成本Lite版，提醒看SWE - bench成绩要关注harness。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3Mzg5MjY3Nw==&amp;chksm=cf241669457161839c224af9b03ddcfb538fbcaf687c1f9e97c57c0b25228e7a1eac0f7383d9&amp;idx=1&amp;mid=2247526485&amp;sn=921f633369ad10dbda497499305cf4a8#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="黄益贺-ai瓶颈扩散至电力" tabindex="-1"><a class="header-anchor" href="#黄益贺-ai瓶颈扩散至电力"><span>黄益贺：AI瓶颈扩散至电力</span></a></h3><p>黄益贺：AI产业链瓶颈正从GPU扩散到电力，存量核电资产因数据中心需求变值钱，引出&#39;过渡期与终局&#39;框架，适用于后续芯片、云等领域。<a href="https://mp.weixin.qq.com/s?__biz=MzkyNzU0MzQwOQ==&amp;chksm=c386857923c77790dace2891dfcafb9b522f963277a705dc11f0eaec1f3f1e8821773922dbe9&amp;idx=1&amp;mid=2247485196&amp;sn=69e075801c76bedc5fe2192e28ceee3d#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="开源动态" tabindex="-1"><a class="header-anchor" href="#开源动态"><span>开源动态</span></a></h2><h3 id="glm-5-2发布-挑战顶级闭源模型" tabindex="-1"><a class="header-anchor" href="#glm-5-2发布-挑战顶级闭源模型"><span>GLM-5.2发布，挑战顶级闭源模型</span></a></h3><p>智谱发布GLM-5.2，具备1M稳定上下文和长程任务能力。在长程任务基准评测中，与顶级闭源模型差距缩小，开源阵营领先，还通过技术应对模型‘作弊’。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3MTkxMjYzOA==&amp;chksm=cf847e50fee9a0e2f286b1584adb6d0392234c1c6ec3fb0038cab386b51cd29eb6209e68fad8&amp;idx=1&amp;mid=2247515689&amp;sn=8b357a66aad5384a9fd9d0f9e7a986a7#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="browseract-让ai-agent像人一样操控浏览器" tabindex="-1"><a class="header-anchor" href="#browseract-让ai-agent像人一样操控浏览器"><span>BrowserAct：让AI Agent像人一样操控浏览器</span></a></h3><p>开源君：BrowserAct是面向AI Agent的浏览器自动化工具，有三层反检测体系等特色功能。它能解决Agent操作浏览器难题，如动态加载、反爬、多账号登录等，值得处理网页任务者一试。<a href="https://mp.weixin.qq.com/s?__biz=MzkwNzU4NTMyMA==&amp;chksm=c125fd8ba8b412f293c8616a39e2e7a71295061ee74c2d1f49987328344db8bde3e5f8026aa7&amp;idx=1&amp;mid=2247506086&amp;sn=323957898e8683be59e4e02f612432ac#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="seedance-2-0仓库-升级ai视频生成流程" tabindex="-1"><a class="header-anchor" href="#seedance-2-0仓库-升级ai视频生成流程"><span>Seedance 2.0仓库：升级AI视频生成流程</span></a></h3><p>开源星探：AI 视频生成存在使用方式单一等问题，<code>seedance - 2.0</code> 仓库把‘提示词’升级为可审计流程，未来竞争关键是工作流等方面能力，这是创作者所需。<a href="https://mp.weixin.qq.com/s?__biz=MzkwMjQ0NzI0OQ==&amp;chksm=c14ab84d1e880bd499ecce754bba32fd5c8e898db1c6319b60c2d0f937230d59d8c19ebb497e&amp;idx=1&amp;mid=2247506340&amp;sn=b8e9c42a0deb25ef3bdb6b407ab0491b#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="《loop-engineering橙皮书》免费开源" tabindex="-1"><a class="header-anchor" href="#《loop-engineering橙皮书》免费开源"><span>《Loop Engineering橙皮书》免费开源</span></a></h3><p>花叔发布32页《Loop Engineering橙皮书》。Loop Engineering由多人推动流行，循环有五个动作，Claude Code的 <code>/goal</code> 和 <code>/loop</code> 命令助力落地，但新手实践有验证债、理解烂等坑。<a href="https://mp.weixin.qq.com/s?__biz=Mzg2OTA1OTAxNA==&amp;chksm=cf6cc0fb0e32e111246549e1b386a0b95a88a242a7b1dce6a84df3662643155effac7bc01014&amp;idx=1&amp;mid=2247490868&amp;sn=19715f5b0f658c9714478ad593facefc#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="算法论文" tabindex="-1"><a class="header-anchor" href="#算法论文"><span>算法论文</span></a></h2><h3 id="南大团队揭秘llm加法运算错误机制" tabindex="-1"><a class="header-anchor" href="#南大团队揭秘llm加法运算错误机制"><span>南大团队揭秘LLM加法运算错误机制</span></a></h3><p>南大团队：大语言模型虽能解决复杂数学题，但在加法运算常出错。团队提出等本位和轨迹与噪声量化模型解释原因，设计推理时纠错法，还指出未来应稳定表征到输出的映射。<a href="https://mp.weixin.qq.com/s?__biz=MzA3MzI4MjgzMw==&amp;chksm=85671504e52fa268711fbf699aff3b4d5fbc43ca626303305730c54e723cd072827198f94acd&amp;idx=2&amp;mid=2651039480&amp;sn=3220e12f92d4f37587dd42bbe398d1a8#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="科学家研发seed神经刺激器挑战疼痛管理" tabindex="-1"><a class="header-anchor" href="#科学家研发seed神经刺激器挑战疼痛管理"><span>科学家研发SEED神经刺激器挑战疼痛管理</span></a></h3><p>纽约大学阿布扎比分校团队：研发出SEED可注射无线神经刺激器，在大鼠实验中实现坐骨神经精准刺激。不过该设备功率传输效率低、有电荷平衡问题，需解决工程难题并通过多项考验。<a href="https://mp.weixin.qq.com/s?__biz=MzA3NTIyODUzNA==&amp;chksm=8690cfbfdc4cc6c1dc9b5bba5c55276f218405b5845285ef2eea79ad1d8227b62c53fd4d9c5b&amp;idx=2&amp;mid=2649798747&amp;sn=de4ee0e663c408a5fa1c32eb7a6f9b46#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="spatial-agent-革新地图agent地理推理" tabindex="-1"><a class="header-anchor" href="#spatial-agent-革新地图agent地理推理"><span>Spatial-Agent：革新地图Agent地理推理</span></a></h3><p>Emory大学等团队：提出Spatial-Agent解决地理空间问答难题，用GeoFlow Graph建模，实验证明对地图任务有效，还指出构建地图类agent需稳定数据源和执行恢复机制。<a href="https://mp.weixin.qq.com/s?__biz=Mzk0MTYzMzMxMA==&amp;chksm=c31e204b1e1b793a81a009b243f7bbad7066de63e532a37f3720468e16318cfd93a77d88339c&amp;idx=2&amp;mid=2247508367&amp;sn=3eef2e12a97b1cc0bb803d8cfeaaa3de#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="蚂蚁egss算法破解tts困局" tabindex="-1"><a class="header-anchor" href="#蚂蚁egss算法破解tts困局"><span>蚂蚁EGSS算法破解TTS困局</span></a></h3><p>蚂蚁集团CodeFuse团队：业界主流TTS方法有计算冗余与选择脆弱问题。为此提出EGSS算法，精准打击痛点，在SWE - Bench上全面突破，用更少Token实现更高准确率，证明聪明计算更有效。<a href="https://mp.weixin.qq.com/s?__biz=MzIzNjc1NzUzMw==&amp;chksm=e99d57e5a29463d52d9785418e47d1690726e10a72c2048d62761c483ce5f7080233b3854419&amp;idx=2&amp;mid=2247897921&amp;sn=842cec7d1241ba72193070a5480460e9#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="王梦迪、丛乐团队推出science-earth系统" tabindex="-1"><a class="header-anchor" href="#王梦迪、丛乐团队推出science-earth系统"><span>王梦迪、丛乐团队推出Science Earth系统</span></a></h3><p>王梦迪、丛乐团队推出Science Earth行星级操作系统，能连接全球科学能力。通过两个案例展示其让不同能力碰撞涌现新问题的作用，靠EACN协调，相关论文、代码已公开。<a href="https://mp.weixin.qq.com/s?__biz=MzIzNjc1NzUzMw==&amp;chksm=e919c96794df5f03524e23aa6eebf4a67f8d2dc8aff152ba3bfe20e56134c78526b8615c4e34&amp;idx=2&amp;mid=2247897842&amp;sn=6c0f752d5de7a0065ba8b58b2ad03f56#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><p style="text-align:center;"><img id="weixin_qr" src="https://meikan-public-images.oss-cn-beijing.aliyuncs.com/imeikan/assets/2025-05-18234303-hub.png" style="max-width:800px;object-fit:cover;"></p><p><a href="https://aireadinghub.com/" target="_blank" rel="noopener noreferrer">官网：www.AiReadingHub.com</a></p>',55)]))}const t=a(s,[["render",d]]),l=JSON.parse('{"path":"/posts/2026-06-17.html","title":"AI日报：科学家：小鼠戒糖反倒血糖更差; 微软纳德拉：AI时代企业要建学习闭环; 章鱼动力获5000万美元融资，推动物理AI进阶","lang":"zh-CN","frontmatter":{"date":"2026-06-17T00:00:00.000Z","title":"AI日报：科学家：小鼠戒糖反倒血糖更差; 微软纳德拉：AI时代企业要建学习闭环; 章鱼动力获5000万美元融资，推动物理AI进阶"},"headers":[{"level":2,"title":"新闻资讯","slug":"新闻资讯","link":"#新闻资讯","children":[{"level":3,"title":"科学家：小鼠戒糖反倒血糖更差","slug":"科学家-小鼠戒糖反倒血糖更差","link":"#科学家-小鼠戒糖反倒血糖更差","children":[]},{"level":3,"title":"微软纳德拉：AI时代企业要建学习闭环","slug":"微软纳德拉-ai时代企业要建学习闭环","link":"#微软纳德拉-ai时代企业要建学习闭环","children":[]},{"level":3,"title":"章鱼动力获5000万美元融资，推动物理AI进阶","slug":"章鱼动力获5000万美元融资-推动物理ai进阶","link":"#章鱼动力获5000万美元融资-推动物理ai进阶","children":[]},{"level":3,"title":"DeepSeek新模型灰度，获500亿融资加速","slug":"deepseek新模型灰度-获500亿融资加速","link":"#deepseek新模型灰度-获500亿融资加速","children":[]},{"level":3,"title":"SpaceX零现金吞AI编程工具Cursor","slug":"spacex零现金吞ai编程工具cursor","link":"#spacex零现金吞ai编程工具cursor","children":[]},{"level":3,"title":"SpaceX 600亿美元收购AI编程工具Cursor","slug":"spacex-600亿美元收购ai编程工具cursor","link":"#spacex-600亿美元收购ai编程工具cursor","children":[]},{"level":3,"title":"SpaceX 600 亿收购 Cursor，马斯克补 AI 短板","slug":"spacex-600-亿收购-cursor-马斯克补-ai-短板","link":"#spacex-600-亿收购-cursor-马斯克补-ai-短板","children":[]},{"level":3,"title":"智谱GLM - 5.2拿下AI编程开源第一","slug":"智谱glm-5-2拿下ai编程开源第一","link":"#智谱glm-5-2拿下ai编程开源第一","children":[]},{"level":3,"title":"Cursor新模型：规模比肩Opus、GPT将发布","slug":"cursor新模型-规模比肩opus、gpt将发布","link":"#cursor新模型-规模比肩opus、gpt将发布","children":[]},{"level":3,"title":"马斯克600亿收购Cursor，抢搭ASI末班车","slug":"马斯克600亿收购cursor-抢搭asi末班车","link":"#马斯克600亿收购cursor-抢搭asi末班车","children":[]}]},{"level":2,"title":"产品应用","slug":"产品应用","link":"#产品应用","children":[{"level":3,"title":"淘宝主播Agent：Harness工程实战揭秘","slug":"淘宝主播agent-harness工程实战揭秘","link":"#淘宝主播agent-harness工程实战揭秘","children":[]},{"level":3,"title":"TokenDance 首发开放智谱 GLM-5.2","slug":"tokendance-首发开放智谱-glm-5-2","link":"#tokendance-首发开放智谱-glm-5-2","children":[]}]},{"level":2,"title":"推荐文章","slug":"推荐文章","link":"#推荐文章","children":[{"level":3,"title":"Claw - SWE - Bench：揭秘编程Agent评测真相","slug":"claw-swe-bench-揭秘编程agent评测真相","link":"#claw-swe-bench-揭秘编程agent评测真相","children":[]},{"level":3,"title":"黄益贺：AI瓶颈扩散至电力","slug":"黄益贺-ai瓶颈扩散至电力","link":"#黄益贺-ai瓶颈扩散至电力","children":[]}]},{"level":2,"title":"开源动态","slug":"开源动态","link":"#开源动态","children":[{"level":3,"title":"GLM-5.2发布，挑战顶级闭源模型","slug":"glm-5-2发布-挑战顶级闭源模型","link":"#glm-5-2发布-挑战顶级闭源模型","children":[]},{"level":3,"title":"BrowserAct：让AI Agent像人一样操控浏览器","slug":"browseract-让ai-agent像人一样操控浏览器","link":"#browseract-让ai-agent像人一样操控浏览器","children":[]},{"level":3,"title":"Seedance 2.0仓库：升级AI视频生成流程","slug":"seedance-2-0仓库-升级ai视频生成流程","link":"#seedance-2-0仓库-升级ai视频生成流程","children":[]},{"level":3,"title":"《Loop Engineering橙皮书》免费开源","slug":"《loop-engineering橙皮书》免费开源","link":"#《loop-engineering橙皮书》免费开源","children":[]}]},{"level":2,"title":"算法论文","slug":"算法论文","link":"#算法论文","children":[{"level":3,"title":"南大团队揭秘LLM加法运算错误机制","slug":"南大团队揭秘llm加法运算错误机制","link":"#南大团队揭秘llm加法运算错误机制","children":[]},{"level":3,"title":"科学家研发SEED神经刺激器挑战疼痛管理","slug":"科学家研发seed神经刺激器挑战疼痛管理","link":"#科学家研发seed神经刺激器挑战疼痛管理","children":[]},{"level":3,"title":"Spatial-Agent：革新地图Agent地理推理","slug":"spatial-agent-革新地图agent地理推理","link":"#spatial-agent-革新地图agent地理推理","children":[]},{"level":3,"title":"蚂蚁EGSS算法破解TTS困局","slug":"蚂蚁egss算法破解tts困局","link":"#蚂蚁egss算法破解tts困局","children":[]},{"level":3,"title":"王梦迪、丛乐团队推出Science Earth系统","slug":"王梦迪、丛乐团队推出science-earth系统","link":"#王梦迪、丛乐团队推出science-earth系统","children":[]}]}],"git":{"updatedTime":1784354567000,"contributors":[{"name":"GitHub Actions","username":"","email":"actions@github.com","commits":1}],"changelog":[{"hash":"f02d8a7ce14a7b9facf26dc9636fe1fbe6ed14ad","time":1784354567000,"email":"actions@github.com","author":"GitHub Actions","message":"Auto-commit generated files on 2026-07-18T06:02:47.235Z"}]},"filePathRelative":"posts/2026-06-17.md","excerpt":"<blockquote>\\n<p>All in AI，看见未来。 每天精选最值得读的AI文章，帮你筛掉时代的噪音。 以简讯见广度，以深读见洞察。 技术、趋势、思考，一站式掌握AI世界。\\n欢迎关注公众号「AI Reading Hub」，获取更多AI资讯和技术文章。</p>\\n</blockquote>\\n<h1>2026-06-17 资讯日报</h1>\\n<h2>新闻资讯</h2>\\n<h3>科学家：小鼠戒糖反倒血糖更差</h3>\\n<p>科威特 Dasman 糖尿病研究所：小鼠实验显示，完全不吃糖的低脂饮食会使小鼠血糖失控、肠道细菌紊乱。这提示均衡营养比单纯戒糖重要，饮食建议或转向维护肠道微生物组。<a href=\\"https://mp.weixin.qq.com/s?__biz=MzA3NTIyODUzNA==&amp;chksm=864ddb6c744fef2ef137c1bf549f62d90cb3353df78b0da9c43015a1f7ef3ac99e364a0b626c&amp;idx=1&amp;mid=2649798747&amp;sn=c6ac92d618ea4bc8adaed006826c038a#rd\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">&gt;阅读原文</a></p>"}');export{t as comp,l as data};
